import{Buffer as i}from"node:buffer";export class WebDAVStorageAdapter{client;config;mode="webdav";constructor(t,e){this.client=t,this.config=e}get configured(){return this.client.configured}async testConnection(){const t=await this.client.testConnection();return{ok:t.ok,message:t.message}}async ensureFolder(t){return this.client.ensureFolder(t)}async uploadFile(t,e,n){return this.client.uploadFile(t,e,n)}async deletePath(t){return this.client.deletePath(t)}getPublicUrl(t){return this.client.getPublicUrl(t)}async downloadFile(t){const e=this.client.getPublicUrl(t),n=`Basic ${i.from(`${this.config.username}:${this.config.password}`).toString("base64")}`,r=await fetch(e,{headers:{Authorization:n},signal:AbortSignal.timeout(3e4)});if(!r.ok)throw new Error(`WebDAV download failed ${r.status}: ${r.statusText}`);const s=await r.arrayBuffer();return i.from(s)}}
